import java.util.Scanner;

public class SafeBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Read entire line

        int maxLength = 10;
        if (input.length() > maxLength) {
            System.out.println("Input string exceeds maximum allowed length.");
            return;
        }

        char[] buffer = new char[maxLength]; // Buffer with fixed size

        // Copy input into buffer with length checking
        for (int i = 0; i < input.length() && i < maxLength; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
